    def test_work_session_effort_budget_counts_steps_duration_and_warnings(self):
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Budgeted work",
            "goal": "Keep resident work bounded.",
            "created_at": "2026-04-17T00:00:00Z",
            "updated_at": "2026-04-17T01:10:00Z",
            "tool_calls": [
                {
                    "id": index + 1,
                    "tool": "read_file",
                    "status": "failed" if index < 2 else "completed",
                    "started_at": "2026-04-17T00:00:00Z",
                    "finished_at": "2026-04-17T00:00:02Z",
                    "parameters": {"path": "README.md"},
                    "result": {"path": "README.md", "text": "body"},
                }
                for index in range(20)
            ],
            "model_turns": [
                {
                    "id": index + 1,
                    "status": "completed",
                    "started_at": "2026-04-17T00:00:10Z",
                    "finished_at": "2026-04-17T00:00:13Z",
                    "action": {"type": "read_file"},
                }
                for index in range(4)
            ],
        }
        task = {"id": 1, "title": "Budgeted work", "status": "ready", "kind": "coding"}

        effort = build_work_session_effort(session, current_time="2026-04-17T01:10:00Z")
        resume = build_work_session_resume(session, task=task, current_time="2026-04-17T01:10:00Z")
        resume_text = format_work_session_resume(resume)
        from mew.work_loop import build_work_model_context

        context = build_work_model_context(
            {"tasks": [task]},
            session,
            task,
            "2026-04-17T01:10:00Z",
        )

        self.assertEqual(effort["steps"]["used"], 24)
        self.assertEqual(effort["steps"]["budget"], 30)
        self.assertEqual(effort["steps"]["remaining"], 6)
        self.assertEqual(effort["steps"]["status"], "near_limit")
        self.assertEqual(effort["tool_calls"]["failed"], 2)
        self.assertEqual(effort["model_turns"]["completed"], 4)
        self.assertEqual(effort["failures"], 2)
        self.assertEqual(effort["effective_tool_failures"], 2)
        self.assertEqual(effort["tool_seconds"], 40.0)
        self.assertEqual(effort["model_seconds"], 12.0)
        self.assertEqual(effort["observed_active_seconds"], 5.0)
        self.assertEqual(effort["wall_elapsed_seconds"], 4200.0)
        self.assertEqual(effort["pressure"], "medium")
        self.assertIn("step_budget_near", effort["warnings"])
        self.assertIn("failure_budget_near", effort["warnings"])
        self.assertIn("wall_time_near", effort["warnings"])
        self.assertEqual(format_work_effort_brief(effort), "effort=medium steps=24/30 failures=2")
        self.assertEqual(resume["effort"]["steps"]["used"], 24)
        self.assertIn("Effort budget", resume_text)
        self.assertIn("pressure=medium steps=24/30 remaining=6 failures=2", resume_text)
        self.assertIn("warnings: step_budget_near, failure_budget_near, wall_time_near", resume_text)
        self.assertEqual(context["work_session"]["effort"]["pressure"], "medium")
        self.assertEqual(context["work_session"]["resume"]["effort"]["steps"]["used"], 24)

    def test_resume_surfaces_same_surface_audit_for_mew_source_edit(self):
        task = {"id": 1, "title": "Audit surface", "status": "ready", "kind": "coding", "notes": ""}
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Audit surface",
            "goal": "Show same-surface audit.",
            "created_at": "2026-04-17T00:00:00Z",
            "updated_at": "2026-04-17T00:01:00Z",
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "edit_file",
                    "status": "completed",
                    "finished_at": "2026-04-17T00:01:00Z",
                    "parameters": {"path": "/tmp/project/src/mew/commands.py"},
                    "result": {"path": "/tmp/project/src/mew/commands.py", "changed": True, "dry_run": True},
                }
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session, task=task)
        audit = resume["same_surface_audit"]
        self.assertEqual(audit["status"], "needed")
        self.assertEqual(audit["paths"], ["src/mew/commands.py"])
        text = format_work_session_resume(resume)
        self.assertIn("Same-surface audit", text)
        self.assertIn("status=needed", text)
        self.assertIn("search nearby command/json/control peers", text)

        session["notes"] = [{"text": "same-surface audit: sibling code path checked", "source": "user"}]
        untimed_note_resume = build_work_session_resume(session, task=task)
        self.assertEqual(untimed_note_resume["same_surface_audit"]["status"], "needed")

        session["notes"] = [
            {
                "created_at": "2026-04-17T00:02:00Z",
                "text": "same-surface audit not done; sibling code path not covered",
                "source": "user",
            }
        ]
        still_needed_resume = build_work_session_resume(session, task=task)
        self.assertEqual(still_needed_resume["same_surface_audit"]["status"], "needed")

        session["notes"].append(
            {
                "created_at": "2026-04-17T00:03:00Z",
                "text": "same-surface audit: sibling code path checked",
                "source": "user",
            }
        )
        noted_resume = build_work_session_resume(session, task=task)
        self.assertEqual(noted_resume["same_surface_audit"]["status"], "noted")

        session["tool_calls"].append(
            {
                "id": 2,
                "tool": "edit_file",
                "status": "completed",
                "finished_at": "2026-04-17T00:04:00Z",
                "parameters": {"path": "/tmp/project/src/mew/other.py"},
                "result": {"path": "/tmp/project/src/mew/other.py", "changed": True},
            }
        )
        newer_edit_resume = build_work_session_resume(session, task=task)
        self.assertEqual(newer_edit_resume["same_surface_audit"]["status"], "needed")

        session["notes"].append(
            {
                "created_at": "2026-04-17T00:05:00Z",
                "text": "same-surface audit: sibling code path checked for the newer edit",
                "source": "user",
            }
        )
        newer_noted_resume = build_work_session_resume(session, task=task)
        self.assertEqual(newer_noted_resume["same_surface_audit"]["status"], "noted")

        session["tool_calls"] = session["tool_calls"][:1]
        session["tool_calls"][0]["result"] = {
            "path": "/tmp/project/src/mew/commands.py",
            "changed": False,
            "dry_run": True,
        }
        no_op_resume = build_work_session_resume(session, task=task)
        self.assertEqual(no_op_resume["same_surface_audit"], {})

    def test_work_session_resume_scores_continuity(self):
        task = {"id": 1, "title": "Continuity", "status": "ready", "kind": "coding", "notes": ""}
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Continuity",
            "goal": "Keep reentry state durable.",
            "created_at": "2026-04-17T00:00:00Z",
            "updated_at": "2026-04-17T00:03:00Z",
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "read_file",
                    "status": "completed",
                    "started_at": "2026-04-17T00:00:00Z",
                    "finished_at": "2026-04-17T00:00:01Z",
                    "parameters": {"path": "README.md"},
                    "result": {"path": "README.md", "text": "body"},
                    "summary": "Read README.md for continuity context.",
                },
                {
                    "id": 2,
                    "tool": "run_tests",
                    "status": "failed",
                    "started_at": "2026-04-17T00:01:00Z",
                    "finished_at": "2026-04-17T00:01:03Z",
                    "parameters": {"command": "python -m pytest"},
                    "result": {"command": "python -m pytest", "exit_code": 1, "stderr": "failed\n"},
                    "error": "tests failed",
                    "summary": "Verifier failed.",
                },
            ],
            "model_turns": [
                {
                    "id": 1,
                    "status": "completed",
                    "started_at": "2026-04-17T00:02:00Z",
                    "finished_at": "2026-04-17T00:02:10Z",
                    "decision_plan": {
                        "working_memory": {
                            "hypothesis": "Continuity is restorable.",
                            "next_step": "Inspect the failed verifier before editing.",
                            "open_questions": ["Which test failed?"],
                            "last_verified_state": "Verifier failed.",
                        }
                    },
                    "action": {"type": "finish"},
                    "summary": "Captured continuity memory.",
                }
            ],
        }

        resume = build_work_session_resume(session, task=task)
        continuity = resume["continuity"]
        text = format_work_session_resume(resume)

        self.assertEqual(continuity["score"], "9/9")
        self.assertEqual(continuity["status"], "strong")
        self.assertEqual(continuity["missing"], [])
        self.assertIn("continuity: 9/9 status=strong", text)
        self.assertTrue(all(axis["ok"] for axis in continuity["axes"]))

    def test_work_continuity_score_requires_concrete_reentry_artifacts(self):
        resume = {
            "phase": "failed",
            "next_action": "think about what happened later",
            "failures": [{"tool_call_id": 7}],
            "context": {"pressure": "low"},
        }

        continuity = build_work_continuity_score(resume)
        resume["continuity"] = continuity

        self.assertIn("working_memory_survived", continuity["missing"])
        self.assertIn("risks_preserved", continuity["missing"])
        self.assertIn("next_action_runnable", continuity["missing"])
        self.assertIn("recovery_path_visible", continuity["missing"])
        self.assertIn("recent_decisions_preserved", continuity["missing"])
        self.assertEqual(continuity["recommendation"]["primary_axis"], "working_memory_survived")
        self.assertIn(
            "refresh working memory",
            continuity["recommendation"]["summary"],
        )
        self.assertIn("plan_items", continuity["recommendation"]["summary"])
        self.assertIn("target_paths", continuity["recommendation"]["summary"])
        self.assertIn("open_questions", continuity["recommendation"]["summary"])
        self.assertIn("continuity_next: refresh working memory", format_work_session_resume(resume))

    def test_work_continuity_score_counts_durable_planning_fields_as_working_memory(self):
        resume = {
            "working_memory": {
                "plan_items": ["inspect continuity"],
                "target_paths": ["src/mew/work_session.py"],
                "open_questions": ["Do durable planning fields count?"],
            },
            "phase": "active",
            "next_action": "continue from preserved plan",
            "context": {"pressure": "low"},
        }

        continuity = build_work_continuity_score(resume)
        axes = {axis["key"]: axis for axis in continuity["axes"]}

        self.assertTrue(axes["working_memory_survived"]["ok"])
        self.assertNotIn("working_memory_survived", continuity["missing"])
        self.assertIn(
            "durable planning fields",
            axes["working_memory_survived"]["reason"],
        )

    def test_work_continuity_score_counts_user_pivot_when_visible(self):
        resume = {
            "phase": "idle",
            "next_action": "continue the work session with /continue",
            "working_memory": {"hypothesis": "Pivot should survive.", "next_step": "Handle queued feedback."},
            "queued_followups": [{"id": 1, "text": "User changed priority."}],
            "recent_decisions": [{"model_turn_id": 1, "action": "finish"}],
            "context": {"pressure": "low"},
        }

        continuity = build_work_continuity_score(resume)
        axis = {item["key"]: item for item in continuity["axes"]}["user_pivot_preserved"]

        self.assertTrue(axis["ok"])
        self.assertEqual(axis["reason"], "pending steer or queued follow-up is visible")

    def test_work_continuity_next_action_requires_runnable_word_or_control(self):
        resume = {
            "phase": "idle",
            "next_action": "Waiting for approval decision",
            "working_memory": {"hypothesis": "Waiting is visible.", "next_step": "Need a real control."},
            "recent_decisions": [{"model_turn_id": 1, "action": "finish"}],
            "context": {"pressure": "low"},
        }

        continuity = build_work_continuity_score(resume)
        axis = {item["key"]: item for item in continuity["axes"]}["next_action_runnable"]

        self.assertFalse(axis["ok"])
        self.assertIn("next_action_runnable", continuity["missing"])

        resume["next_action"] = "continue the work session with mew work 1 --live"
        continuity = build_work_continuity_score(resume)
        axis = {item["key"]: item for item in continuity["axes"]}["next_action_runnable"]
        self.assertTrue(axis["ok"])

    def test_work_continuity_recovery_path_requires_actionable_control(self):
        resume = {
            "phase": "failed",
            "next_action": "retry the safe read",
            "working_memory": {"hypothesis": "Recovery is needed.", "next_step": "Retry only with controls."},
            "failures": [{"tool_call_id": 7, "summary": "read interrupted"}],
            "recovery_plan": {
                "next_action": "retry the safe read",
                "items": [
                    {
                        "tool_call_id": 7,
                        "action": "retry_tool",
                        "reason": "read was interrupted",
                        "hint": "retry this read manually",
                    }
                ],
            },
            "recent_decisions": [{"model_turn_id": 1, "action": "finish"}],
            "context": {"pressure": "low"},
        }

        continuity = build_work_continuity_score(resume)
        axes = {item["key"]: item for item in continuity["axes"]}

        self.assertFalse(axes["recovery_path_visible"]["ok"])
        self.assertIn("recovery_path_visible", continuity["missing"])

        resume["recovery_plan"]["items"][0]["hint"] = "mew work 1 --session --resume --allow-read . --auto-recover-safe"
        continuity = build_work_continuity_score(resume)
        axes = {item["key"]: item for item in continuity["axes"]}
        self.assertTrue(axes["recovery_path_visible"]["ok"])

