    def test_work_session_resume_compresses_prior_think(self):
        task = {"id": 1, "title": "Compressed think", "status": "ready", "kind": "coding", "notes": ""}
        turns = []
        for index in range(10):
            turn_id = index + 1
            turns.append(
                {
                    "id": turn_id,
                    "status": "completed",
                    "started_at": f"2026-04-17T00:{index:02d}:00Z",
                    "finished_at": f"2026-04-17T00:{index:02d}:01Z",
                    "guidance_snapshot": f"Guidance {turn_id}",
                    "decision_plan": {
                        "working_memory": {
                            "hypothesis": f"Hypothesis {turn_id}",
                            "next_step": f"Next step {turn_id}",
                            "plan_items": [
                                f"Plan item {turn_id}A",
                                f"Plan item {turn_id}B",
                                f"Plan item {turn_id}C",
                                f"Plan item {turn_id}D",
                            ],
                            "target_paths": [
                                f"src/path_{turn_id}.py",
                                f"tests/test_path_{turn_id}.py",
                            ],
                            "open_questions": [
                                f"Question {turn_id}A",
                                f"Question {turn_id}B",
                                f"Question {turn_id}C",
                                f"Question {turn_id}D",
                            ],
                            "last_verified_state": f"Verified {turn_id}",
                        }
                    },
                    "action": {"type": "read_file"},
                    "summary": f"Turn summary {turn_id}",
                }
            )
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Compressed think",
            "goal": "Preserve older reasoning after compaction.",
            "created_at": "2026-04-17T00:00:00Z",
            "updated_at": "2026-04-17T00:09:01Z",
            "tool_calls": [],
            "model_turns": turns,
        }

        resume = build_work_session_resume(session, task=task, limit=3)
        prior = resume["compressed_prior_think"]
        text = format_work_session_resume(resume)

        self.assertEqual(prior["total_older_model_turns"], 7)
        self.assertEqual(prior["shown"], 4)
        self.assertEqual(prior["items"][-1]["model_turn_id"], 7)
        self.assertEqual(prior["items"][-1]["hypothesis"], "Hypothesis 7")
        self.assertEqual(
            prior["items"][-1]["plan_items"],
            ["Plan item 7A", "Plan item 7B", "Plan item 7C"],
        )
        self.assertEqual(
            prior["items"][-1]["target_paths"],
            ["src/path_7.py", "tests/test_path_7.py"],
        )
        self.assertEqual(
            prior["items"][-1]["open_questions"],
            ["Question 7A", "Question 7B", "Question 7C"],
        )
        self.assertIn("Compressed prior think (4/7 older turn(s))", text)
        self.assertIn("#7 [completed] read_file Turn summary 7", text)
        self.assertIn("  plan_items:", text)
        self.assertIn("  - Plan item 7A", text)
        self.assertIn("  target_paths: src/path_7.py, tests/test_path_7.py", text)
        self.assertIn("  open_questions:", text)
        self.assertIn("  - Question 7A", text)
        self.assertIn("  - Question 7C", text)
        self.assertNotIn("Plan item 7D", text)
        self.assertNotIn("Question 7D", text)

    def test_work_session_effort_uses_current_time_for_active_wall_pressure(self):
        active_session = {
            "id": 1,
            "status": "active",
            "created_at": "2026-04-17T00:00:00Z",
            "updated_at": "2026-04-17T00:05:00Z",
            "tool_calls": [],
            "model_turns": [],
        }
        closed_session = dict(active_session, status="closed")

        with patch("mew.work_session.now_iso", return_value="2026-04-17T04:00:00Z"):
            active_effort = build_work_session_effort(active_session)
            closed_effort = build_work_session_effort(closed_session)

        self.assertEqual(active_effort["wall_elapsed_seconds"], 14400.0)
        self.assertEqual(active_effort["pressure"], "high")
        self.assertIn("wall_time_high", active_effort["warnings"])
        self.assertEqual(closed_effort["wall_elapsed_seconds"], 300.0)
        self.assertEqual(closed_effort["pressure"], "low")

    def test_work_tool_repeat_guard_detects_consecutive_and_total_repeats(self):
        parameters = {"path": "README.md", "max_chars": 12000}
        session = {
            "tool_calls": [
                {"id": 1, "tool": "read_file", "parameters": parameters, "status": "completed"},
                {"id": 2, "tool": "search_text", "parameters": {"query": "mew"}, "status": "completed"},
                {"id": 3, "tool": "read_file", "parameters": parameters, "status": "completed"},
                {"id": 4, "tool": "read_file", "parameters": dict(reversed(list(parameters.items()))), "status": "failed"},
            ]
        }

        guard = work_tool_repeat_guard(session, "read_file", parameters)

        self.assertEqual(guard["reason"], "consecutive_repeat")
        self.assertEqual(guard["consecutive_count"], 2)
        self.assertEqual(guard["total_count"], 3)
        self.assertEqual(guard["matching_tool_call_ids"], [1, 3, 4])
        self.assertIn("repeat-action guard blocked read_file", guard["message"])
        self.assertIn("incorporate any prior rejection or review feedback", guard["message"])

        total_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "read_file", "parameters": parameters},
                    {"id": 2, "tool": "search_text", "parameters": {"query": "mew"}},
                    {"id": 3, "tool": "read_file", "parameters": parameters},
                    {"id": 4, "tool": "glob", "parameters": {"pattern": "*.py"}},
                    {"id": 5, "tool": "read_file", "parameters": parameters},
                    {"id": 6, "tool": "inspect_dir", "parameters": {"path": "."}},
                    {"id": 7, "tool": "read_file", "parameters": parameters},
                ]
            },
            "read_file",
            parameters,
        )

        self.assertEqual(total_guard["reason"], "total_repeat")
        self.assertEqual(total_guard["total_count"], 4)

        default_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "read_file", "parameters": {"path": "README.md"}},
                    {
                        "id": 2,
                        "tool": "read_file",
                        "parameters": {
                            "path": "README.md",
                            "offset": 0,
                            "allow_verify": True,
                            "reason": "same read with a different reason",
                        },
                    },
                ]
            },
            "read_file",
            {"path": "README.md", "offset": "0", "summary": "same read again"},
        )

        self.assertEqual(default_guard["reason"], "consecutive_repeat")

        line_window_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "read_file", "parameters": {"path": "README.md", "line_start": 10}},
                    {
                        "id": 2,
                        "tool": "read_file",
                        "parameters": {"path": "README.md", "line_start": "10", "line_count": 120},
                    },
                ]
            },
            "read_file",
            {"path": "README.md", "line_start": 10, "line_count": "120"},
        )

        self.assertEqual(line_window_guard["reason"], "consecutive_repeat")

        ignored_line_count_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "read_file", "parameters": {"path": "README.md", "line_count": 12}},
                    {"id": 2, "tool": "read_file", "parameters": {"path": "README.md"}},
                ]
            },
            "read_file",
            {"path": "README.md", "line_count": 999},
        )

        self.assertEqual(ignored_line_count_guard["reason"], "consecutive_repeat")

        command_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "run_tests", "parameters": {"command": "uv run python -m unittest"}},
                    {
                        "id": 2,
                        "tool": "run_tests",
                        "parameters": {"command": "uv run python -m unittest", "cwd": ".", "timeout": 300},
                    },
                ]
            },
            "run_tests",
            {"command": "uv run python -m unittest", "timeout": "300", "allow_verify": True},
        )

        self.assertEqual(command_guard["reason"], "consecutive_repeat")

        inspect_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "inspect_dir", "parameters": {"path": ".", "limit": 999}},
                    {"id": 2, "tool": "inspect_dir", "parameters": {"path": ".", "limit": 200}},
                ]
            },
            "inspect_dir",
            {"path": ".", "limit": 200},
        )

        self.assertEqual(inspect_guard["reason"], "consecutive_repeat")

        git_log_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "git_log", "parameters": {"cwd": ".", "limit": 0}},
                    {"id": 2, "tool": "git_log", "parameters": {"cwd": ".", "limit": 1}},
                ]
            },
            "git_log",
            {"cwd": ".", "limit": 1},
        )

        self.assertEqual(git_log_guard["reason"], "consecutive_repeat")

        search_guard = work_tool_repeat_guard(
            {
                "tool_calls": [
                    {"id": 1, "tool": "search_text", "parameters": {"query": "mew", "path": ".", "max_matches": 999}},
                    {"id": 2, "tool": "search_text", "parameters": {"query": "mew", "path": ".", "max_matches": 200}},
                ]
            },
            "search_text",
            {"query": "mew", "path": ".", "max_matches": 200, "context_lines": 3},
        )

        self.assertEqual(search_guard["reason"], "consecutive_repeat")

    def test_first_unquoted_shell_operator_respects_quotes_and_adjacency(self):
        self.assertEqual(first_unquoted_shell_operator("python -V&& python -V"), ("&&", "chain"))
        self.assertEqual(first_unquoted_shell_operator("python -V >out.txt"), (">", "redirection"))
        self.assertEqual(first_unquoted_shell_operator("python -V 2>out.txt"), ("2>", "redirection"))
        self.assertEqual(first_unquoted_shell_operator("python -V &>out.txt"), ("&>", "redirection"))
        self.assertEqual(first_unquoted_shell_operator("python -V\nfalse"), ("\n", "chain"))
        self.assertEqual(first_unquoted_shell_operator("printf '&&'"), (None, ""))
        self.assertEqual(first_unquoted_shell_operator('python -c "print(1 > 0)"'), (None, ""))

    def test_create_work_session_refreshes_existing_task_snapshot(self):
        state = {"tasks": [], "work_sessions": [], "next_ids": {"work_session": 1}}
        task = add_coding_task(state)
        session, created = create_work_session(state, task, current_time="first")

        self.assertTrue(created)
        self.assertEqual(session["title"], "Build native hands")
        self.assertEqual(session["goal"], "Exercise a native work session.")

        task["title"] = "Build sharper hands"
        task["description"] = "Use the latest task focus."
        reused, reused_created = create_work_session(state, task, current_time="second")

        self.assertFalse(reused_created)
        self.assertEqual(reused["id"], session["id"])
        self.assertEqual(reused["title"], "Build sharper hands")
        self.assertEqual(reused["goal"], "Use the latest task focus.")
        self.assertEqual(reused["updated_at"], "second")

