    def test_work_session_cells_capture_model_command_diff_and_approval(self):
        session = {
            "id": 3,
            "task_id": 9,
            "status": "active",
            "title": "Cell cockpit",
            "model_turns": [
                {
                    "id": 1,
                    "status": "completed",
                    "started_at": "2026-04-18T00:00:00Z",
                    "finished_at": "2026-04-18T00:00:01Z",
                    "action": {"type": "run_tests"},
                    "summary": "verify",
                    "tool_call_id": 2,
                    "guidance_snapshot": "Run the narrow verifier.",
                }
            ],
            "tool_calls": [
                {
                    "id": 2,
                    "tool": "run_tests",
                    "status": "completed",
                    "started_at": "2026-04-18T00:00:02Z",
                    "finished_at": "2026-04-18T00:00:05Z",
                    "parameters": {"command": "uv run pytest -q", "cwd": "."},
                    "result": {
                        "command": "uv run pytest -q",
                        "cwd": ".",
                        "exit_code": 0,
                        "stdout": "1 passed\n2 passed\n",
                        "stderr": "",
                    },
                },
                {
                    "id": 3,
                    "tool": "edit_file",
                    "status": "completed",
                    "started_at": "2026-04-18T00:00:06Z",
                    "finished_at": "2026-04-18T00:00:07Z",
                    "parameters": {"path": "README.md"},
                    "result": {
                        "path": "README.md",
                        "dry_run": True,
                        "changed": True,
                        "diff": "--- a/README.md\n+++ b/README.md\n@@ -1 +1 @@\n-old\n+new\n",
                        "diff_stats": {"added": 1, "removed": 1},
                    },
                },
            ],
        }

        cells = build_work_session_cells(session, limit=None)

        self.assertEqual([cell["kind"] for cell in cells], ["model_turn", "test", "diff", "approval"])
        self.assertEqual(cells[0]["id"], "s3:model_turn:1")
        self.assertEqual(cells[1]["id"], "s3:test:2")
        self.assertEqual(cells[1]["tail"][0]["stream"], "stdout")
        self.assertIn("2 passed", cells[1]["tail"][0]["lines"])
        self.assertEqual(cells[3]["status"], "pending")
        self.assertEqual(cells[3]["operation"], "file_write")
        self.assertEqual(cells[3]["target"], "README.md")
        self.assertIn("--approve-tool 3", cells[3]["actions"]["approve_once"])
        self.assertIn("--verify-command 'uv run pytest -q'", cells[3]["actions"]["approve_once"])
        self.assertIn("--reject-reason <feedback>", cells[3]["actions"]["reject_with_feedback"])
        self.assertEqual(cells[2]["operation"], "edit_file")
        self.assertEqual(cells[2]["target"], "README.md")
        self.assertEqual(cells[2]["diff_stats"], {"added": 1, "removed": 1})
        self.assertTrue(cells[2]["dry_run"])
        self.assertIn("approval needed", cells[3]["preview"])

        text = format_work_session_cells(session, limit=None)
        self.assertIn("Work cells #3 [active] task=#9", text)
        self.assertIn("- test [completed] run_tests exit=0 duration=3.0s uv run pytest -q", text)
        self.assertIn("id: s3:test:2", text)
        self.assertIn("elapsed: 3.0s", text)
        self.assertIn("command: uv run pytest -q", text)
        self.assertIn("exit=0", text)
        self.assertIn("stdout: 2 lines", text)
        self.assertIn("stderr: 0 lines 0 chars", text)
        self.assertIn("full_output: mew work 9 --tests", text)
        self.assertIn("stdout_tail:", text)
        self.assertIn("diff_stats: +1 -1", text)
        self.assertIn("full_diff: mew work 9 --diffs", text)
        self.assertIn("- approval [pending] approval needed", text)
        self.assertIn("operation: file_write", text)
        self.assertIn("approve_once: mew work 9 --approve-tool 3 --allow-write README.md --allow-verify --verify-command 'uv run pytest -q'", text)
        self.assertIn("reject_with_feedback: mew work 9 --reject-tool 3 --reject-reason <feedback>", text)
        self.assertIn("id: s3:approval:3", text)

    def test_source_edit_approval_surfaces_missing_test_pairing(self):
        session = {
            "id": 3,
            "task_id": 9,
            "status": "active",
            "title": "Pairing",
            "model_turns": [
                {
                    "id": 1,
                    "status": "completed",
                    "tool_call_ids": [3],
                    "action": {"type": "batch"},
                    "summary": "edit source only",
                }
            ],
            "tool_calls": [
                {
                    "id": 3,
                    "tool": "edit_file",
                    "status": "completed",
                    "parameters": {"path": "src/mew/pairing.py"},
                    "result": {
                        "path": "src/mew/pairing.py",
                        "dry_run": True,
                        "changed": True,
                        "diff": "--- a/src/mew/pairing.py\n+++ b/src/mew/pairing.py\n@@ -1 +1 @@\n-old\n+new\n",
                        "diff_stats": {"added": 1, "removed": 1},
                    },
                },
            ],
        }

        resume = build_work_session_resume(session)
        approval = resume["pending_approvals"][0]
        cells = build_work_session_cells(session, limit=None)
        approval_cell = [cell for cell in cells if cell["kind"] == "approval"][0]
        text = format_work_session_cells(session, limit=None)
        resume_text = format_work_session_resume(resume)

        self.assertEqual(approval["pairing_status"]["status"], "missing_test_edit")
        self.assertTrue(approval["pairing_status"]["advisory"])
        self.assertEqual(approval["pairing_status"]["suggested_test_path"], "tests/test_pairing.py")
        self.assertEqual(approval["approve_hint"], "")
        self.assertEqual(approval["cli_approve_hint"], "")
        self.assertIn("--allow-unpaired-source-edit", approval["override_approve_hint"])
        self.assertEqual(approval_cell["pairing_status"]["status"], "missing_test_edit")
        self.assertIn("paired test missing", approval_cell["preview"])
        self.assertNotIn("approve_once", approval_cell["actions"])
        self.assertIn("--allow-unpaired-source-edit", approval_cell["actions"]["override_approve_once"])
        self.assertIn("approve_once_blocked: add a paired tests/** write/edit first", text)
        self.assertIn("override_approve_once: mew work 9 --approve-tool 3", text)
        self.assertIn("pairing_status: missing_test_edit", text)
        self.assertIn("suggested_test_path: tests/test_pairing.py", text)
        self.assertIn("pairing_status: missing_test_edit", resume_text)
        self.assertIn("suggested_test_path: tests/test_pairing.py", resume_text)
        self.assertIn("approve blocked: add a paired tests/** write/edit before approving", resume_text)
        self.assertIn("--allow-unpaired-source-edit", resume_text)

    def test_resume_discovers_existing_test_before_convention_pairing_path(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("src/mew").mkdir(parents=True)
                Path("tests").mkdir()
                Path("src/mew/cli.py").write_text(
                    "def build_parser():\n    return None\n\n"
                    "def main():\n    return 0\n",
                    encoding="utf-8",
                )
                Path("tests/test_dogfood.py").write_text(
                    "from mew.cli import build_parser\n\n"
                    "def test_cli_dogfood_m2_task_shape_choices():\n"
                    "    parser = build_parser()\n"
                    "    assert parser is not None\n",
                    encoding="utf-8",
                )
                Path("tests/test_desk.py").write_text(
                    "from mew.cli import main\n\n"
                    "def test_desk_main_imports():\n"
                    "    assert main() == 0\n",
                    encoding="utf-8",
                )
                session = {
                    "id": 9,
                    "task_id": 9,
                    "status": "active",
                    "title": "Add dogfood m2 task shape CLI option",
                    "notes": [{"text": "The paired test should cover dogfood m2 task shape parser behavior."}],
                    "tool_calls": [
                        {
                            "id": 3,
                            "tool": "edit_file",
                            "status": "completed",
                            "parameters": {
                                "path": "src/mew/cli.py",
                                "old": "old",
                                "new": "new --m2-task-shape dogfood",
                            },
                            "result": {
                                "path": "src/mew/cli.py",
                                "dry_run": True,
                                "changed": True,
                                "diff": "+ dogfood m2_task_shape parser option\n",
                            },
                        },
                    ],
                    "model_turns": [],
                }

                resume = build_work_session_resume(session)
                approval = resume["pending_approvals"][0]
                pairing = approval["pairing_status"]
                text = format_work_session_resume(resume)

                self.assertEqual(pairing["status"], "missing_test_edit")
                self.assertEqual(pairing["suggested_test_path"], "tests/test_dogfood.py")
                self.assertNotEqual(pairing["suggested_test_path"], "tests/test_cli.py")
                self.assertEqual(pairing["discovered_test_paths"][0], "tests/test_dogfood.py")
                self.assertIn("imports mew.cli", pairing["suggestion_reason"])
                self.assertIn("suggested_test_path: tests/test_dogfood.py", text)
            finally:
                os.chdir(old_cwd)

