    def test_work_reply_template_steers_when_hidden_unpaired_source_blocks_approve_all(self):
        tool_calls = [
            {
                "id": 1,
                "tool": "edit_file",
                "status": "completed",
                "parameters": {"path": "src/mew/hidden.py"},
                "result": {
                    "path": "src/mew/hidden.py",
                    "dry_run": True,
                    "changed": True,
                    "diff": "--- a/src/mew/hidden.py\n+++ b/src/mew/hidden.py\n@@ -1 +1 @@\n-old\n+new\n",
                },
            }
        ]
        for index in range(2, 10):
            tool_calls.append(
                {
                    "id": index,
                    "tool": "edit_file",
                    "status": "completed",
                    "parameters": {"path": f"notes/{index}.md"},
                    "result": {
                        "path": f"notes/{index}.md",
                        "dry_run": True,
                        "changed": True,
                        "diff": f"--- a/notes/{index}.md\n+++ b/notes/{index}.md\n@@ -1 +1 @@\n-old\n+new\n",
                    },
                }
            )
        session = {
            "id": 3,
            "task_id": 9,
            "status": "active",
            "updated_at": "2026-04-18T00:00:00Z",
            "tool_calls": tool_calls,
            "model_turns": [],
        }

        resume = build_work_session_resume(session, limit=8)
        schema = build_work_reply_schema(session, resume=resume)

        self.assertEqual([approval["tool_call_id"] for approval in resume["pending_approvals"]], list(range(2, 10)))
        self.assertEqual(schema["reply_template"]["actions"][0]["type"], "steer")
        self.assertIn("hidden src/mew source edit", schema["reply_template"]["actions"][0]["text"])
        self.assertEqual(schema["approve_all_blocked_reason"], resume["approve_all_blocked_reason"])
        self.assertEqual(schema["blocked_approve_all_hint"], resume["blocked_approve_all_hint"])
        self.assertEqual(schema["override_approve_all_hint"], resume["override_approve_all_hint"])
        self.assertFalse(any(action["type"] == "approve_all" for action in schema["supported_actions"]))

