    def test_narrow_pytest_selectors_do_not_replace_broad_default_verify_command(self):
        broad_command = "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q"
        narrow_commands = [
            "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q tests/test_work_session.py",
            "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q tests/test_work_session.py::WorkSessionTests::test_example",
            "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q -m slow",
            "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q --lf",
            "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q --deselect tests/test_work_session.py::test_example",
        ]

        for command in narrow_commands:
            with self.subTest(command=command):
                session = {"default_options": {"allow_verify": True, "verify_command": broad_command}}
                remember_successful_work_verification(
                    session,
                    "run_tests",
                    {"exit_code": 0, "command": command},
                )
                self.assertEqual(session["default_options"]["verify_command"], broad_command)

    def test_first_narrow_pytest_selector_does_not_become_default_verify_command(self):
        session = {"default_options": {}}
        result = {
            "exit_code": 0,
            "command": "UV_CACHE_DIR=/tmp/uv-cache uv run pytest -q tests/test_work_session.py::WorkSessionTests::test_example",
        }

        remember_successful_work_verification(session, "run_tests", result)

        self.assertTrue(result["narrow_verify_command"])
        self.assertNotIn("verify_command", session["default_options"])
        call = {"tool": "run_tests", "result": result}
        self.assertEqual(latest_work_verify_command([call]), "")
        self.assertEqual(
            work_session_default_verify_command({"default_options": session["default_options"], "tool_calls": [call]}),
            "",
        )

    def test_source_edit_approval_marks_paired_test_write_ok(self):
        session = {
            "id": 3,
            "task_id": 9,
            "status": "active",
            "title": "Pairing",
            "model_turns": [
                {
                    "id": 1,
                    "status": "completed",
                    "tool_call_ids": [3, 4],
                    "action": {"type": "batch"},
                    "summary": "edit source and tests",
                }
            ],
            "tool_calls": [
                {
                    "id": 3,
                    "tool": "edit_file",
                    "status": "completed",
                    "parameters": {"path": "src/mew/pairing.py"},
                    "result": {
                        "path": "src/mew/pairing.py",
                        "dry_run": True,
                        "changed": True,
                        "diff": "--- a/src/mew/pairing.py\n+++ b/src/mew/pairing.py\n@@ -1 +1 @@\n-old\n+new\n",
                    },
                },
                {
                    "id": 4,
                    "tool": "write_file",
                    "status": "completed",
                    "parameters": {"path": "tests/test_pairing.py"},
                    "result": {
                        "path": "tests/test_pairing.py",
                        "dry_run": True,
                        "changed": True,
                        "diff": "--- /dev/null\n+++ b/tests/test_pairing.py\n@@ -0,0 +1 @@\n+def test_pairing(): pass\n",
                    },
                },
            ],
        }

        resume = build_work_session_resume(session)
        source_approval = [
            approval for approval in resume["pending_approvals"] if approval["path"] == "src/mew/pairing.py"
        ][0]
        test_approval = [
            approval for approval in resume["pending_approvals"] if approval["path"] == "tests/test_pairing.py"
        ][0]
        cells = build_work_session_cells(session, limit=None)
        source_approval_cell = [
            cell for cell in cells if cell["kind"] == "approval" and cell["target"] == "src/mew/pairing.py"
        ][0]

        self.assertEqual(source_approval["pairing_status"]["status"], "ok")
        self.assertEqual(source_approval["pairing_status"]["paired_tool_call_id"], 4)
        self.assertEqual(source_approval_cell["pairing_status"]["status"], "ok")
        self.assertNotIn("pairing_status", test_approval)
        self.assertNotIn("paired test missing", source_approval_cell["preview"])

