    def test_work_session_context_and_resume_surface_user_preferences(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.work_loop import build_work_model_context, build_work_think_prompt

                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                preference = "Prefer compact diffs over noisy full logs."
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["memory", "--add", preference, "--category", "preferences"]), 0)
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                state = load_state()
                session = state["work_sessions"][0]
                task = state["tasks"][0]
                context = build_work_model_context(state, session, task, "now")
                preferences = context["work_session"]["resume"]["user_preferences"]
                self.assertEqual(preferences["source"], "memory.deep.preferences")
                self.assertEqual(preferences["total"], 1)
                self.assertFalse(preferences["truncated"])
                self.assertIn(preference, preferences["items"][0])
                self.assertIn(preference, build_work_think_prompt(context))

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                resume = json.loads(stdout.getvalue())["resume"]
                self.assertIn(preference, resume["user_preferences"]["items"][0])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume"]), 0)
                text = stdout.getvalue()
                self.assertIn("User preferences", text)
                self.assertIn(preference, text)
            finally:
                os.chdir(old_cwd)

    def test_plan_work_model_turn_extends_timeout_for_write_ready_fast_path(self):
        from mew.work_loop import (
            WORK_WRITE_READY_FAST_PATH_MODEL_TIMEOUT_SECONDS,
            WORK_WRITE_READY_TINY_DRAFT_MODEL_TIMEOUT_SECONDS,
            plan_work_model_turn,
        )
        from mew.work_session import finish_work_model_turn, start_work_model_turn

        state = {"next_ids": {"work_model_turn": 1}, "work_sessions": []}
        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Fast path timeout",
            "goal": "Draft a paired dry-run edit.",
            "created_at": "then",
            "updated_at": "then",
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "read_file",
                    "status": "completed",
                    "parameters": {"path": "src/mew/workbench.py", "line_start": 120, "line_count": 41},
                    "result": {
                        "path": "src/mew/workbench.py",
                        "line_start": 120,
                        "line_end": 160,
                        "text": "".join(f"source_line_{index}\n" for index in range(41)),
                        "next_line": 161,
                        "context_truncated": False,
                        "source_truncated": False,
                        "truncated": False,
                    },
                },
                {
                    "id": 2,
                    "tool": "read_file",
                    "status": "completed",
                    "parameters": {"path": "tests/test_workbench.py", "line_start": 32, "line_count": 12},
                    "result": {
                        "path": "tests/test_workbench.py",
                        "line_start": 32,
                        "line_end": 43,
                        "text": "".join(f"test_line_{index}\n" for index in range(12)),
                        "next_line": 44,
                        "context_truncated": False,
                        "source_truncated": False,
                        "truncated": False,
                    },
                },
            ],
            "model_turns": [],
        }
        state["work_sessions"].append(session)
        task = {
            "id": 1,
            "title": "Fast path timeout",
            "description": "Draft a paired dry-run edit.",
            "status": "todo",
            "kind": "coding",
        }
        decision_plan = {
            "summary": "prepare paired dry-run edit",
            "working_memory": {
                "hypothesis": "The paired source/test windows are enough for a dry-run edit.",
                "next_step": "Draft one paired dry-run edit batch.",
                "plan_items": [
                    "Draft one paired dry-run edit batch.",
                    "Run focused verifier after approval.",
                ],
                "target_paths": ["src/mew/workbench.py", "tests/test_workbench.py"],
                "last_verified_state": "Exact paired windows are cached and complete.",
            },
        }
        turn = start_work_model_turn(
            state,
            session,
            decision_plan,
            {"summary": "prepare paired dry-run edit"},
            {"type": "wait", "reason": "next slice is clear"},
        )
        finish_work_model_turn(state, 1, turn["id"])

        observed = []

        def fake_model(model_backend, model_auth, prompt, model, base_url, timeout, log_prefix=None, **kwargs):
            observed.append({"prompt": prompt, "timeout": timeout})
            if "Write-ready tiny draft lane is active." in prompt:
                return {"summary": "wait", "action": {"type": "wait", "reason": "stop"}}
            return {"summary": "wait", "action": {"type": "wait", "reason": "stop"}}

        with patch("mew.work_loop.call_model_json_with_retries", side_effect=fake_model):
            planned = plan_work_model_turn(
                state,
                session,
                task,
                {"path": "auth.json"},
                timeout=60,
                allowed_read_roots=["."],
                allowed_write_roots=["."],
                allow_verify=True,
                verify_command="uv run python -m unittest tests.test_workbench",
                act_mode="deterministic",
            )

        self.assertEqual(len(observed), 2)
        self.assertEqual(observed[0]["timeout"], WORK_WRITE_READY_TINY_DRAFT_MODEL_TIMEOUT_SECONDS)
        self.assertIn("Write-ready tiny draft lane is active.", observed[0]["prompt"])
        self.assertEqual(observed[1]["timeout"], WORK_WRITE_READY_FAST_PATH_MODEL_TIMEOUT_SECONDS)
        self.assertIn("Write-ready fast path is active.", observed[1]["prompt"])
        self.assertTrue(planned["model_metrics"]["write_ready_fast_path"])
        self.assertEqual(planned["model_metrics"]["draft_phase"], "write_ready")
        self.assertEqual(planned["model_metrics"]["draft_attempts"], 1)
        self.assertEqual(planned["model_metrics"]["cached_window_ref_count"], 2)
        self.assertEqual(len(planned["model_metrics"]["cached_window_hashes"]), 2)
        self.assertTrue(
            all(str(item).startswith("sha1:") for item in planned["model_metrics"]["cached_window_hashes"])
        )
        self.assertEqual(planned["model_metrics"]["draft_prompt_contract_version"], "v2")
        self.assertGreater(planned["model_metrics"]["draft_prompt_static_chars"], 0)
        self.assertGreater(planned["model_metrics"]["draft_prompt_dynamic_chars"], 0)
        self.assertEqual(planned["model_metrics"]["tiny_write_ready_draft_prompt_contract_version"], "v3")
        self.assertTrue(planned["model_metrics"]["tiny_write_ready_draft_attempted"])
        self.assertEqual(planned["model_metrics"]["tiny_write_ready_draft_outcome"], "fallback")
        self.assertEqual(planned["model_metrics"]["tiny_write_ready_draft_fallback_reason"], "invalid_shape")
        self.assertEqual(
            planned["model_metrics"]["tiny_write_ready_draft_timeout_seconds"],
            WORK_WRITE_READY_TINY_DRAFT_MODEL_TIMEOUT_SECONDS,
        )
        self.assertEqual(planned["model_metrics"]["tiny_write_ready_draft_exit_stage"], "unknown_kind")
        self.assertGreaterEqual(planned["model_metrics"]["tiny_write_ready_draft_elapsed_seconds"], 0.0)
        self.assertGreaterEqual(planned["model_metrics"]["tiny_write_ready_draft_timeout_budget_utilization"], 0.0)
        self.assertLess(
            planned["model_metrics"]["tiny_write_ready_draft_prompt_chars"],
            planned["model_metrics"]["think"]["prompt_chars"],
        )
        self.assertEqual(
            planned["model_metrics"]["think"]["timeout_seconds"],
            WORK_WRITE_READY_FAST_PATH_MODEL_TIMEOUT_SECONDS,
        )
        self.assertEqual(planned["model_metrics"]["draft_runtime_mode"], "guarded")

    def test_tiny_write_ready_draft_reasoning_effort_respects_auto_and_env_override_source(self):
        from mew.work_loop import _attempt_write_ready_tiny_draft_turn

        class _EffortScope:
            def __init__(self, observed):
                self.observed = observed

            def __call__(self, effort):
                self.observed.append(effort)

                class _Context:
                    def __enter__(self_inner):
                        return None

                    def __exit__(self_inner, exc_type, exc, tb):
                        return False

                return _Context()

        for inherited_source, inherited_effort, expected_reasoning_effort, expected_source in (
            ("auto", "medium", "low", "tiny_draft_auto_override"),
            ("auto", "high", "low", "tiny_draft_auto_override"),
            ("env_override", "xhigh", "xhigh", "env_override"),
        ):
            observed_scope = []
            with self.subTest(
                inherited_reasoning_source=inherited_source,
                inherited_reasoning_effort=inherited_effort,
            ):
                with patch(
                    "mew.work_loop.codex_reasoning_effort_scope",
                    side_effect=_EffortScope(observed_scope),
                ):
                    with patch("mew.work_loop.call_model_json_with_retries", return_value="invalid-shape"):
                        result = _attempt_write_ready_tiny_draft_turn(
                            session={"id": "write"},
                            context={},
                            tiny_context={},
                            write_ready_fast_path={},
                            model_auth={},
                            model="codex",
                            base_url="",
                            model_backend="codex",
                            timeout=60,
                            reasoning_effort_source=inherited_source,
                            reasoning_effort=inherited_effort,
                        )
                self.assertEqual(observed_scope, [expected_reasoning_effort])
                metrics = result["metrics"]
                self.assertEqual(
                    metrics["tiny_write_ready_draft_inherited_reasoning_effort"],
                    inherited_effort,
                )
                self.assertEqual(metrics["tiny_write_ready_draft_inherited_reasoning_effort_source"], inherited_source)
                self.assertEqual(metrics["tiny_write_ready_draft_reasoning_effort"], expected_reasoning_effort)
                self.assertEqual(metrics["tiny_write_ready_draft_reasoning_effort_source"], expected_source)

    def test_tiny_write_ready_draft_pre_model_sink_records_reasoning_effort_context(self):
        from mew.work_loop import WORK_WRITE_READY_TINY_DRAFT_REASONING_EFFORT
        from mew.work_loop import plan_work_model_turn

        scenario = self._load_patch_draft_fixture_scenario("paired_src_test_happy")
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                for path, payload in (scenario.get("live_files") or {}).items():
                    file_path = Path(path)
                    file_path.parent.mkdir(parents=True, exist_ok=True)
                    file_path.write_text(payload["text"], encoding="utf-8")

                with state_lock():
                    state = load_state()
                    task, session = self._seed_write_ready_shadow_session(state, scenario)

                pre_model_payloads = []

                def fake_model(model_backend, model_auth, prompt, model, base_url, timeout, log_prefix=None, **kwargs):
                    if log_prefix and "work_write_ready_tiny_draft" in str(log_prefix):
                        raise TimeoutError("timed out while generating tiny draft")
                    return {"summary": "wait", "action": {"type": "wait", "reason": "stop"}}

                for source, effort, expected_reasoning_effort, expected_reasoning_source in (
                    ("auto", "high", WORK_WRITE_READY_TINY_DRAFT_REASONING_EFFORT, "tiny_draft_auto_override"),
                    ("env_override", "xhigh", "xhigh", "env_override"),
                ):
                    pre_model_payloads = []
                    with self.subTest(inherited_reasoning_source=source, inherited_reasoning_effort=effort):
                        pre_model_payloads = []

                        def capture_pre_model_metrics(metrics):
                            pre_model_payloads.append(metrics)

                        with patch(
                            "mew.work_loop.select_work_reasoning_policy",
                            return_value={"effort": effort, "source": source},
                        ):
                            with patch("mew.work_loop.call_model_json_with_retries", side_effect=fake_model):
                                planned = plan_work_model_turn(
                                    state,
                                    session,
                                    task,
                                    {"path": "auth.json"},
                                    allowed_read_roots=["."],
                                    allowed_write_roots=scenario.get("allowed_write_roots") or ["."],
                                    allow_verify=True,
                                    verify_command="uv run python -m unittest tests.test_patch_draft",
                                    act_mode="deterministic",
                                    pre_model_metrics_sink=capture_pre_model_metrics,
                                )

                        self.assertTrue(pre_model_payloads)
                        self.assertNotIn(
                            "tiny_write_ready_draft_exit_stage",
                            pre_model_payloads[0],
                        )
                        self.assertEqual(
                            pre_model_payloads[0]["tiny_write_ready_draft_reasoning_effort"],
                            expected_reasoning_effort,
                        )
                        self.assertEqual(
                            pre_model_payloads[0]["tiny_write_ready_draft_reasoning_effort_source"],
                            expected_reasoning_source,
                        )
                        self.assertEqual(
                            pre_model_payloads[0]["tiny_write_ready_draft_inherited_reasoning_effort"],
                            effort,
                        )
                        self.assertEqual(
                            pre_model_payloads[0]["tiny_write_ready_draft_inherited_reasoning_effort_source"],
                            source,
                        )
                        metrics = planned["model_metrics"]
                        self.assertEqual(metrics["tiny_write_ready_draft_reasoning_effort"], expected_reasoning_effort)
                        self.assertEqual(metrics["tiny_write_ready_draft_reasoning_effort_source"], expected_reasoning_source)
                        self.assertEqual(metrics["tiny_write_ready_draft_inherited_reasoning_effort"], effort)
                        self.assertEqual(metrics["tiny_write_ready_draft_inherited_reasoning_effort_source"], source)
            finally:
                os.chdir(old_cwd)

    def test_tiny_write_ready_draft_lane_promotes_compiler_patch_blocker_to_wait(self):
        from mew.work_loop import (
            _attempt_write_ready_tiny_draft_turn,
            _work_write_ready_fast_path_details,
            build_work_model_context,
            build_write_ready_tiny_draft_model_context,
        )

        scenario = self._load_patch_draft_fixture_scenario("paired_src_test_happy")
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                for path, payload in (scenario.get("live_files") or {}).items():
                    file_path = Path(path)
                    file_path.parent.mkdir(parents=True, exist_ok=True)
                    file_path.write_text(payload["text"], encoding="utf-8")

                with state_lock():
                    state = load_state()
                    task, session = self._seed_write_ready_shadow_session(state, scenario)

                context = build_work_model_context(
                    state,
                    session,
                    task,
                    "",
                    allowed_read_roots=["."],
                    allowed_write_roots=scenario.get("allowed_write_roots") or ["."],
                )
                tiny_context = build_write_ready_tiny_draft_model_context(context)
                write_ready_fast_path = _work_write_ready_fast_path_details(context)

                def fake_model(model_backend, model_auth, prompt, model, base_url, timeout, log_prefix=None, **kwargs):
                    return {
                        "kind": "patch_proposal",
                        "summary": "update source without paired test edit",
                        "files": [
                            {
                                "path": "src/mew/patch_draft.py",
                                "edits": [{"old": "return 41", "new": "return 42"}],
                            }
                        ],
                    }

                with patch("mew.work_loop.call_model_json_with_retries", side_effect=fake_model):
                    result = _attempt_write_ready_tiny_draft_turn(
                        session=session,
                        context=context,
                        tiny_context=tiny_context,
                        write_ready_fast_path=write_ready_fast_path,
                        model_auth={"path": "auth.json"},
                        model="codex",
                        base_url="https://example.invalid",
                        model_backend="codex",
                        timeout=60,
                        allowed_write_roots=scenario.get("allowed_write_roots") or ["."],
                    )

                self.assertEqual(result["status"], "blocker")
                self.assertEqual(
                    result["action"],
                    {"type": "wait", "reason": "write-ready tiny draft blocker: unpaired_source_edit_blocked"},
                )
                metrics = result["metrics"]
                self.assertEqual(metrics["tiny_write_ready_draft_outcome"], "blocker")
                self.assertEqual(metrics["tiny_write_ready_draft_exit_stage"], "compiler_blocker")
                self.assertEqual(metrics["tiny_write_ready_draft_fallback_reason"], "")
                self.assertEqual(metrics["tiny_write_ready_draft_compiler_artifact_kind"], "patch_blocker")
                self.assertTrue(metrics["patch_draft_compiler_ran"])
                self.assertEqual(metrics["patch_draft_compiler_artifact_kind"], "patch_blocker")
                self.assertTrue(metrics["patch_draft_compiler_replay_path"])
                self.assertTrue(Path(metrics["patch_draft_compiler_replay_path"]).is_file())
            finally:
                os.chdir(old_cwd)

