    def test_work_session_context_and_resume_surface_active_typed_memory(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.work_loop import build_work_model_context, build_work_think_prompt

                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                with redirect_stdout(StringIO()):
                    self.assertEqual(
                        main(
                            [
                                "memory",
                                "--add",
                                "User prefers narrow verification before broad pytest.",
                                "--type",
                                "user",
                                "--scope",
                                "private",
                                "--name",
                                "Verification preference",
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(
                        main(
                            [
                                "memory",
                                "--add",
                                "Native hands work should surface active typed memory recall during startup.",
                                "--type",
                                "project",
                                "--scope",
                                "private",
                                "--name",
                                "Native hands recall",
                                "--description",
                                "Typed recall belongs in resident startup context.",
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)

                state = load_state()
                session = state["work_sessions"][0]
                task = state["tasks"][0]
                context = build_work_model_context(state, session, task, "now")
                active_memory = context["work_session"]["resume"]["active_memory"]
                self.assertEqual(active_memory["source"], ".mew/memory")
                self.assertGreaterEqual(active_memory["total"], 2)
                self.assertTrue(
                    any(item["memory_type"] == "user" for item in active_memory["items"]),
                    active_memory,
                )
                self.assertTrue(
                    any(item["memory_type"] == "project" for item in active_memory["items"]),
                    active_memory,
                )
                prompt = build_work_think_prompt(context)
                self.assertIn("work_session.resume.active_memory", prompt)
                self.assertIn("User prefers narrow verification", prompt)
                self.assertIn("Typed recall belongs in resident startup context.", prompt)

                compact_context = build_work_model_context(
                    state,
                    session,
                    task,
                    "now",
                    prompt_context_mode="compact_memory",
                )
                compact_active_memory = compact_context["work_session"]["resume"]["active_memory"]
                self.assertTrue(compact_active_memory["compacted_for_prompt"])
                self.assertTrue(compact_active_memory["items"])
                self.assertNotIn("text", compact_active_memory["items"][0])
                compact_prompt = build_work_think_prompt(compact_context)
                self.assertIn("active_memory.compacted_for_prompt", compact_prompt)
                self.assertIn("Typed recall belongs in resident startup context.", compact_prompt)
                self.assertIn("Do not use read_file on .mew/memory/private paths", compact_prompt)
                self.assertNotIn("Native hands work should surface active typed memory", compact_prompt)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                resume = json.loads(stdout.getvalue())["resume"]
                self.assertTrue(resume["active_memory"]["items"])

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume"]), 0)
                text = stdout.getvalue()
                self.assertIn("Active memory", text)
                self.assertIn("Verification preference", text)
                self.assertIn("Native hands recall", text)
                self.assertIn("created_at=", text)
            finally:
                os.chdir(old_cwd)

    def test_work_loop_model_calls_disable_transient_retries(self):
        from mew.work_loop import call_model_json_with_retries

        with patch("mew.work_loop._work_model_timeout_guard_available", return_value=False):
            with patch(
                "mew.work_loop._agent_call_model_json_with_retries",
                return_value={"summary": "ok", "action": {"type": "finish"}},
            ) as call_model:
                result = call_model_json_with_retries(
                    "codex",
                    {"path": "auth.json"},
                    "prompt",
                    "gpt-5.4",
                    "https://example.invalid",
                    45,
                    log_prefix="work_think codex session=1",
                )

        self.assertEqual(result["summary"], "ok")
        self.assertEqual(call_model.call_count, 1)
        self.assertEqual(call_model.call_args.kwargs["retry_delays"], ())

    def test_work_loop_model_calls_enforce_hard_timeout_without_retries(self):
        if not hasattr(os, "fork"):
            self.skipTest("requires fork context")

        from mew.errors import ModelBackendError
        from mew.work_loop import call_model_json_with_retries

        def slow_model(*args, **kwargs):
            time.sleep(0.2)
            return {"summary": "late", "action": {"type": "finish"}}

        started = time.monotonic()
        with patch("mew.work_loop._agent_call_model_json_with_retries", side_effect=slow_model):
            with self.assertRaisesRegex(ModelBackendError, "request timed out"):
                call_model_json_with_retries(
                    "codex",
                    {"path": "auth.json"},
                    "prompt",
                    "gpt-5.4",
                    "https://example.invalid",
                    0.05,
                    log_prefix="work_think codex session=1",
                )

        self.assertLess(time.monotonic() - started, 0.2)

    def test_work_loop_model_calls_fall_back_after_child_crash(self):
        from mew.work_loop import call_model_json_with_retries

        class FakeRecvConn:
            def poll(self, timeout):
                return True

            def recv(self):
                raise EOFError

            def close(self):
                return None

        class FakeSendConn:
            def close(self):
                return None

        class FakeProcess:
            def start(self):
                return None

            def is_alive(self):
                return False

            def join(self, timeout=None):
                return None

            def terminate(self):
                return None

        class FakeContext:
            def Pipe(self, duplex=False):
                return FakeRecvConn(), FakeSendConn()

            def Process(self, target=None, args=(), daemon=False):
                return FakeProcess()

        with patch("mew.work_loop._work_model_timeout_guard_available", return_value=True):
            with patch("mew.work_loop.multiprocessing.get_context", return_value=FakeContext()):
                with patch(
                    "mew.work_loop._call_model_json_without_guard",
                    return_value={"summary": "fallback ok", "action": {"type": "finish"}},
                ) as call_model:
                    result = call_model_json_with_retries(
                        "codex",
                        {"path": "auth.json"},
                        "prompt",
                        "gpt-5.4",
                        "https://example.invalid",
                        45,
                        log_prefix="work_think codex session=1",
                    )

        self.assertEqual(result["summary"], "fallback ok")
        self.assertEqual(call_model.call_count, 1)

    def test_compact_model_turns_for_prompt_collapses_redundant_planning_churn(self):
        from mew.work_session import compact_model_turns_for_prompt

        turns = [
            {"id": 1, "status": "completed", "action": {"type": "read_file"}},
            {
                "id": 2,
                "status": "failed",
                "action": {"type": "wait"},
                "summary": "model turn failed: request timed out",
                "error": "request timed out",
            },
            {
                "id": 3,
                "status": "interrupted",
                "action": {"type": "planning"},
                "summary": "planning work step",
                "error": "Interrupted before the work model turn completed.",
            },
            {
                "id": 4,
                "status": "failed",
                "action": {"type": "wait"},
                "summary": "model turn failed: request timed out",
                "error": "request timed out",
            },
            {"id": 5, "status": "completed", "action": {"type": "run_tests"}},
            {
                "id": 6,
                "status": "failed",
                "action": {"type": "wait"},
                "summary": "model turn failed: request timed out",
                "error": "request timed out",
            },
            {
                "id": 7,
                "status": "interrupted",
                "action": {"type": "planning"},
                "summary": "planning work step",
                "error": "Interrupted before the work model turn completed.",
            },
        ]

        compacted = compact_model_turns_for_prompt(turns)
        self.assertEqual([turn["id"] for turn in compacted], [1, 4, 5, 7])

    def test_active_memory_terms_filter_self_improve_boilerplate(self):
        terms = active_memory_terms(
            task={
                "title": "Improve mew itself",
                "description": (
                    "Improve mew through one small, reviewable code or documentation change.\n\n"
                    "Focus:\nUse active memory dogfood to pick and execute the next small mew improvement\n\n"
                    "Recently completed git commits. Do not repeat these topics:\n"
                    "a4310dd Expose active memory debug view\n\n"
                    "Constraints:\n- Keep the change small.\n"
                ),
                "kind": "coding",
            }
        )

        self.assertIn("active", terms)
        self.assertIn("memory", terms)
        self.assertIn("dogfood", terms)
        self.assertIn("execute", terms)
        for noisy in (
            "improve",
            "mew",
            "itself",
            "through",
            "small",
            "reviewable",
            "recently",
            "completed",
            "a4310dd",
            "expose",
            "view",
            "constraints",
        ):
            self.assertNotIn(noisy, terms)

