    def test_work_resume_uses_recorded_output_review_after_failed_command(self):
        from mew.work_session import build_work_session_resume, format_work_session_resume

        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Recover command",
            "goal": "Recover command failure.",
            "updated_at": "now",
            "tool_calls": [
                {
                    "id": 7,
                    "tool": "run_command",
                    "status": "completed",
                    "parameters": {"command": "uv run pytest -q", "cwd": "."},
                    "result": {
                        "command": "uv run pytest -q",
                        "cwd": ".",
                        "exit_code": 1,
                        "stdout": "failed",
                        "stderr": "",
                    },
                    "summary": "tests failed",
                }
            ],
            "model_turns": [],
        }

        resume = build_work_session_resume(session)
        reobserve = resume["suggested_safe_reobserve"]
        item = resume["recovery_plan"]["items"][0]
        self.assertEqual(reobserve["source_tool_call_id"], 7)
        self.assertEqual(reobserve["kind"], "recorded_output_review")
        self.assertNotIn("action", reobserve)
        self.assertEqual(reobserve["parameters"]["command"], "uv run pytest -q")
        self.assertEqual(item["action"], "needs_user_review")
        self.assertEqual(item["safety"], "command")
        self.assertEqual(item["effect_classification"], "action_committed")
        self.assertEqual(item["command"], "uv run pytest -q")
        self.assertEqual(item["cwd"], ".")
        self.assertEqual(item["exit_code"], 1)
        self.assertEqual(item["stdout_tail"], "failed")
        self.assertIn("failed after execution", item["reason"])

        text = format_work_session_resume(resume)
        self.assertIn("review: recorded_output_review", text)
        self.assertIn("effect=action_committed", text)
        self.assertIn("cwd: .", text)
        self.assertIn("exit: 1", text)
        self.assertNotIn("review_command_output", text)

    def test_work_session_resume_auto_recovers_safe_read_tool(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("auto recover me\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    state["work_sessions"].append(
                        {
                            "id": 1,
                            "task_id": 1,
                            "status": "active",
                            "title": "Build native hands",
                            "goal": "Auto recover read.",
                            "created_at": "then",
                            "updated_at": "then",
                            "last_tool_call_id": 1,
                            "last_model_turn_id": 1,
                            "tool_calls": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "tool": "read_file",
                                    "status": "interrupted",
                                    "parameters": {"path": "README.md"},
                                    "result": None,
                                    "summary": "",
                                    "error": "",
                                    "started_at": "then",
                                    "finished_at": "then",
                                }
                            ],
                            "model_turns": [
                                {
                                    "id": 1,
                                    "session_id": 1,
                                    "task_id": 1,
                                    "status": "interrupted",
                                    "decision_plan": {},
                                    "action_plan": {},
                                    "action": {"type": "read_file", "path": "README.md"},
                                    "tool_call_id": 1,
                                    "summary": "",
                                    "error": "",
                                    "started_at": "then",
                                    "finished_at": "then",
                                }
                            ],
                        }
                    )
                    save_state(state)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(["work", "1", "--session", "--resume", "--allow-read", ".", "--auto-recover-safe", "--json"]),
                        0,
                    )
                payload = json.loads(stdout.getvalue())
                self.assertEqual(payload["auto_recovery"]["recovery"]["action"], "retry_tool")
                self.assertIn("world_state_before", payload["auto_recovery"]["recovery"])
                self.assertEqual(payload["auto_recovery"]["tool_call"]["status"], "completed")
                self.assertEqual(payload["resume"]["phase"], "idle")
                self.assertIn("auto recover me", payload["auto_recovery"]["tool_call"]["result"]["text"])

                session = load_state()["work_sessions"][0]
                self.assertEqual(session["tool_calls"][0]["recovery_status"], "superseded")
                self.assertEqual(session["tool_calls"][0]["recovered_by_tool_call_id"], 2)
                self.assertEqual(session["model_turns"][0]["recovery_status"], "superseded")

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--allow-read", "."]), 0)
                self.assertNotIn("Recovery plan", stdout.getvalue())
            finally:
                os.chdir(old_cwd)

