    def test_work_session_approve_all_verifies_after_entire_batch(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "write_file",
                                "--path",
                                "one.md",
                                "--content",
                                "one\n",
                                "--create",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "write_file",
                                "--path",
                                "two.md",
                                "--content",
                                "two\n",
                                "--create",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )

                verify_command = (
                    f"{sys.executable} -c \"from pathlib import Path; "
                    "assert Path('one.md').read_text() == 'one\\n'; "
                    "assert Path('two.md').read_text() == 'two\\n'\""
                )
                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--approve-all",
                                "--allow-write",
                                ".",
                                "--allow-verify",
                                "--verify-command",
                                verify_command,
                                "--json",
                            ]
                        ),
                        0,
                    )
                data = json.loads(stdout.getvalue())

                self.assertEqual(data["count"], 2)
                first_apply = data["approved"][0]["tool_call"]
                second_apply = data["approved"][1]["tool_call"]
                self.assertTrue(first_apply["result"]["verification_deferred"])
                self.assertNotIn("verification_exit_code", first_apply["result"])
                self.assertEqual(second_apply["result"]["verification_exit_code"], 0)
                self.assertEqual(Path("one.md").read_text(encoding="utf-8"), "one\n")
                self.assertEqual(Path("two.md").read_text(encoding="utf-8"), "two\n")
            finally:
                os.chdir(old_cwd)

    def test_work_session_approve_all_rolls_back_deferred_writes_when_final_verify_fails(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("a.txt").write_text("old a\n", encoding="utf-8")
                Path("b.txt").write_text("old b\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)
                with redirect_stdout(StringIO()):
                    self.assertEqual(main(["work", "1", "--start-session"]), 0)
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "a.txt",
                                "--old",
                                "old a",
                                "--new",
                                "bad a",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--tool",
                                "edit_file",
                                "--path",
                                "b.txt",
                                "--old",
                                "old b",
                                "--new",
                                "good b",
                                "--allow-write",
                                ".",
                            ]
                        ),
                        0,
                    )

                verify_command = (
                    f"{sys.executable} -c \"from pathlib import Path; "
                    "assert Path('a.txt').read_text() == 'good a\\n'; "
                    "assert Path('b.txt').read_text() == 'good b\\n'\""
                )
                with redirect_stdout(StringIO()):
                    self.assertEqual(
                        main(
                            [
                                "work",
                                "1",
                                "--approve-all",
                                "--allow-write",
                                ".",
                                "--allow-verify",
                                "--verify-command",
                                verify_command,
                                "--json",
                            ]
                        ),
                        1,
                    )

                self.assertEqual(Path("a.txt").read_text(encoding="utf-8"), "old a\n")
                self.assertEqual(Path("b.txt").read_text(encoding="utf-8"), "old b\n")
                session = load_state()["work_sessions"][0]
                first_apply = session["tool_calls"][2]
                second_apply = session["tool_calls"][3]
                self.assertEqual(first_apply["status"], "failed")
                self.assertTrue(first_apply["result"]["rolled_back"])
                self.assertIn("batch verification failed", first_apply["result"]["batch_rollback_reason"])
                self.assertEqual(second_apply["status"], "failed")
                self.assertTrue(second_apply["result"]["rolled_back"])
            finally:
                os.chdir(old_cwd)

