    def test_work_ai_blocks_third_identical_tool_call_before_execution(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("loop guard content\n", encoding="utf-8")
                parameters = {
                    "path": "README.md",
                    "allowed_write_roots": [],
                    "allow_shell": False,
                    "allow_verify": False,
                    "verify_cwd": ".",
                    "verify_timeout": 300,
                    "max_chars": 12000,
                }
                with state_lock():
                    state = load_state()
                    from mew.state import add_question

                    task = add_coding_task(state)
                    add_question(state, "Need product input?")
                    session, _created = create_work_session(state, task)
                    for _index in range(2):
                        call = start_work_tool_call(state, session, "read_file", parameters)
                        finish_work_tool_call(
                            state,
                            session["id"],
                            call["id"],
                            result={
                                "path": "README.md",
                                "size": 19,
                                "text": "loop guard content\n",
                                "offset": 0,
                                "truncated": False,
                            },
                        )
                    save_state(state)

                model_output = {"summary": "read README again", "action": {"type": "read_file", "path": "README.md"}}
                with patch("mew.commands.load_model_auth", return_value={"path": "auth.json"}):
                    with patch("mew.work_loop.call_model_json_with_retries", return_value=model_output):
                        with redirect_stdout(StringIO()):
                            self.assertEqual(
                                main(
                                    [
                                        "work",
                                        "1",
                                        "--live",
                                        "--quiet",
                                        "--auth",
                                        "auth.json",
                                        "--allow-read",
                                        ".",
                                        "--act-mode",
                                        "deterministic",
                                    ]
                                ),
                                1,
                            )

                session = load_state()["work_sessions"][0]
                self.assertEqual(len(session["tool_calls"]), 3)
                blocked_call = session["tool_calls"][-1]
                self.assertEqual(blocked_call["status"], "failed")
                self.assertIn("repeat-action guard blocked read_file", blocked_call["error"])
                self.assertEqual(blocked_call["repeat_guard"]["reason"], "consecutive_repeat")
                self.assertIsNone(blocked_call["result"])
                self.assertEqual(blocked_call["repeat_guard"]["matching_tool_call_ids"], [1, 2])
                suggested_actions = blocked_call["repeat_guard"]["suggested_actions"]
                self.assertEqual(suggested_actions[0]["kind"], "review_work_session")
                self.assertIn("mew work 1 --session --resume --allow-read .", suggested_actions[0]["command"])
                self.assertEqual(suggested_actions[1]["kind"], "steer_work_session")
                self.assertIn("mew work 1 --steer '<guidance>'", suggested_actions[1]["command"])
                self.assertTrue(any(action.get("kind") == "reply" for action in suggested_actions))
                self.assertEqual(session["model_turns"][-1]["status"], "failed")
                from mew.work_loop import work_tool_call_for_model

                self.assertEqual(
                    work_tool_call_for_model(blocked_call)["repeat_guard"]["reason"],
                    "consecutive_repeat",
                )
                self.assertEqual(
                    work_tool_call_for_model(blocked_call)["repeat_guard"]["suggested_actions"][0]["kind"],
                    "review_work_session",
                )
                snapshot = json.loads(Path(".mew/follow/latest.json").read_text(encoding="utf-8"))
                self.assertEqual(snapshot["stop_reason"], "tool_failed")
                self.assertEqual(snapshot["last_step"]["tool_call"]["repeat_guard"]["reason"], "consecutive_repeat")
                self.assertEqual(
                    snapshot["last_step"]["tool_call"]["repeat_guard"]["suggested_actions"][1]["kind"],
                    "steer_work_session",
                )
            finally:
                os.chdir(old_cwd)

    def test_work_ai_blocks_broad_read_after_same_path_search_miss_before_execution(self):
        import mew.commands as commands_module

        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("src/mew").mkdir(parents=True)
                Path("src/mew/work_session.py").write_text("VALUE = 'resident body'\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                model_outputs = [
                    {
                        "summary": "search continuity symbol",
                        "working_memory": {
                            "hypothesis": "Need the continuity helper span.",
                            "next_step": "Search the known target path before reading.",
                            "target_paths": ["src/mew/work_session.py"],
                        },
                        "action": {
                            "type": "search_text",
                            "path": "src/mew/work_session.py",
                            "query": "missing continuity symbol",
                        },
                    },
                    {
                        "summary": "read from the top anyway",
                        "working_memory": {
                            "hypothesis": "Need the continuity helper span.",
                            "next_step": "Read the full file from the top.",
                            "target_paths": ["src/mew/work_session.py"],
                        },
                        "action": {
                            "type": "read_file",
                            "path": "src/mew/work_session.py",
                        },
                    },
                ]

                original_execute = commands_module.execute_work_tool_with_output

                def guarded_execute(tool, parameters, allowed_read_roots, output_progress=None):
                    if tool == "read_file":
                        raise AssertionError("broad read should have been blocked before execution")
                    return original_execute(tool, parameters, allowed_read_roots, output_progress)

                with patch("mew.commands.load_model_auth", return_value={"path": "auth.json"}):
                    with patch("mew.work_loop.call_model_json_with_retries", side_effect=model_outputs):
                        with patch("mew.commands.execute_work_tool_with_output", side_effect=guarded_execute):
                            with redirect_stdout(StringIO()) as stdout:
                                self.assertEqual(
                                    main(
                                        [
                                            "work",
                                            "1",
                                            "--live",
                                            "--quiet",
                                            "--auth",
                                            "auth.json",
                                            "--allow-read",
                                            ".",
                                            "--act-mode",
                                            "deterministic",
                                            "--max-steps",
                                            "2",
                                        ]
                                    ),
                                    1,
                                )

                session = load_state()["work_sessions"][0]
                self.assertEqual(len(session["tool_calls"]), 2)
                blocked_call = session["tool_calls"][-1]
                self.assertEqual(blocked_call["tool"], "read_file")
                self.assertEqual(blocked_call["status"], "failed")
                self.assertIn("broad-read guard blocked read_file", blocked_call["error"])
                self.assertEqual(blocked_call["broad_read_guard"]["reason"], "broad_read_after_search_miss")
                self.assertEqual(blocked_call["broad_read_guard"]["search_tool_call_id"], 1)
                self.assertEqual(blocked_call["broad_read_guard"]["path"], "src/mew/work_session.py")
                from mew.work_loop import work_tool_call_for_model

                self.assertEqual(
                    work_tool_call_for_model(blocked_call)["broad_read_guard"]["reason"],
                    "broad_read_after_search_miss",
                )
                snapshot = json.loads(Path(".mew/follow/latest.json").read_text(encoding="utf-8"))
                self.assertEqual(snapshot["stop_reason"], "tool_failed")
                self.assertEqual(
                    snapshot["last_step"]["tool_call"]["broad_read_guard"]["reason"],
                    "broad_read_after_search_miss",
                )
                self.assertIn("stop=tool_failed", stdout.getvalue())
            finally:
                os.chdir(old_cwd)

    def test_work_ai_persists_think_working_memory_to_resume(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("hello reentry memory\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                model_output = {
                    "summary": "read README",
                    "working_memory": {
                        "hypothesis": "README is the next evidence source.",
                        "next_step": "Read README.md before editing.",
                        "open_questions": ["Does README mention the target behavior?"],
                        "last_verified_state": "not verified yet",
                    },
                    "action": {"type": "read_file", "path": "README.md"},
                }
                with patch("mew.commands.load_model_auth", return_value={"path": "auth.json"}):
                    with patch("mew.work_loop.call_model_json_with_retries", return_value=model_output) as call_model:
                        with redirect_stdout(StringIO()) as stdout:
                            self.assertEqual(
                                main(
                                    [
                                        "work",
                                        "1",
                                        "--ai",
                                        "--auth",
                                        "auth.json",
                                        "--allow-read",
                                        ".",
                                        "--act-mode",
                                        "deterministic",
                                        "--json",
                                    ]
                                ),
                                0,
                            )

                data = json.loads(stdout.getvalue())
                self.assertEqual(call_model.call_count, 1)
                self.assertEqual(data["steps"][0]["tool_call"]["status"], "completed")
                session = load_state()["work_sessions"][0]
                self.assertEqual(
                    session["model_turns"][0]["decision_plan"]["working_memory"]["hypothesis"],
                    "README is the next evidence source.",
                )

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume", "--json"]), 0)
                resume = json.loads(stdout.getvalue())["resume"]
                memory = resume["working_memory"]
                self.assertEqual(memory["hypothesis"], "README is the next evidence source.")
                self.assertEqual(memory["next_step"], "Read README.md before editing.")
                self.assertEqual(memory["target_paths"], ["README.md"])
                self.assertEqual(memory["open_questions"], ["Does README mention the target behavior?"])
                self.assertEqual(memory["source"], "think")
                self.assertEqual(memory["latest_tool_call_id"], 1)
                self.assertIn("latest tool #1 completed read_file", memory["latest_tool_state"])
                self.assertEqual(memory["stale_after_tool_call_id"], 1)

                with redirect_stdout(StringIO()) as stdout:
                    self.assertEqual(main(["work", "1", "--session", "--resume"]), 0)
                text = stdout.getvalue()
                self.assertIn("Working memory", text)
                self.assertIn("hypothesis: README is the next evidence source.", text)
                self.assertIn("stale_next_step: Read README.md before editing.", text)
                self.assertIn("target_paths: README.md", text)
                self.assertNotIn("\nnext_step: Read README.md before editing.", text)
                self.assertIn("latest_tool_state: latest tool #1 completed read_file", text)
                self.assertIn("stale_after_tool_call: #1", text)
            finally:
                os.chdir(old_cwd)

