    def test_work_live_prompt_approval_can_reject_dry_run_write_inline(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                Path("README.md").write_text("old text\n", encoding="utf-8")
                with state_lock():
                    state = load_state()
                    add_coding_task(state)
                    save_state(state)

                model_outputs = [
                    {
                        "summary": "preview edit",
                        "action": {
                            "type": "edit_file",
                            "path": "README.md",
                            "old": "old text",
                            "new": "new text",
                        },
                    },
                    {
                        "summary": "should not rerun rejected edit",
                        "action": {
                            "type": "edit_file",
                            "path": "README.md",
                            "old": "old text",
                            "new": "new text",
                            "apply": True,
                        },
                    },
                ]
                verify_command = f"{sys.executable} -c \"print('verify ok')\""
                with patch("mew.commands.load_model_auth", return_value={"path": "auth.json"}):
                    with patch("mew.work_loop.call_model_json_with_retries", side_effect=model_outputs) as call_model:
                        with patch("sys.stdin", StringIO("n\n")):
                            with redirect_stdout(StringIO()) as stdout, redirect_stderr(StringIO()):
                                self.assertEqual(
                                    main(
                                        [
                                            "work",
                                            "1",
                                            "--live",
                                            "--auth",
                                            "auth.json",
                                            "--allow-read",
                                            ".",
                                            "--allow-write",
                                            ".",
                                            "--allow-verify",
                                            "--verify-command",
                                            verify_command,
                                            "--prompt-approval",
                                            "--max-steps",
                                            "2",
                                            "--act-mode",
                                            "deterministic",
                                        ]
                                    ),
                                    0,
                                )

                output = stdout.getvalue()
                self.assertIn("Diff preview (+1 -1)", output)
                self.assertIn("-old text", output)
                self.assertIn("+new text", output)
                self.assertIn(f"Verify on approval: {verify_command}", output)
                self.assertIn("Apply dry-run work tool #1 edit_file", output)
                self.assertIn("README.md? [y/N/q]:", output)
                self.assertIn("rejected work tool #1", output)
                self.assertIn("inline_approval=rejected", output)
                self.assertIn("stop=approval_rejected", output)
                self.assertEqual(call_model.call_count, 1)
                self.assertEqual(Path("README.md").read_text(encoding="utf-8"), "old text\n")
                rejected = load_state()["work_sessions"][0]["tool_calls"][0]
                self.assertEqual(rejected["approval_status"], "rejected")
                self.assertEqual(rejected["rejection_reason"], "inline approval rejected")
                state = load_state()
                rejected = state["work_sessions"][0]["tool_calls"][0]
                question_id = rejected.get("approval_question_id")
                self.assertEqual(rejected["approval_prompt_status"], "answered")
                question = [item for item in state["questions"] if item["id"] == question_id][0]
                self.assertEqual(question["source"], "work_approval")
                self.assertEqual(question["status"], "answered")
                self.assertIn("Work session #1 tool #1 is waiting for approval.", question["text"])
                self.assertIn("Rejected work tool #1", state["replies"][0]["text"])
            finally:
                os.chdir(old_cwd)

