    def test_search_text_marks_truncated_when_more_matches_exist(self):
        from mew.read_tools import search_text, summarize_read_result

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            for index in range(3):
                (root / f"hit{index}.txt").write_text("needle\n", encoding="utf-8")

            result = search_text("needle", str(root), [str(root)], max_matches=2, context_lines=0)

            self.assertEqual(len(result["matches"]), 2)
            self.assertTrue(result["truncated"])
            summary = summarize_read_result("search_text", result)
            self.assertIn("matches=2 (truncated)", summary)

    def test_search_text_accepts_query_that_starts_with_dash(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "cli.txt").write_text("mew task list --status pending\n", encoding="utf-8")

            result = search_text("--status", str(root), [str(root)], max_matches=5, context_lines=0)

            self.assertEqual(len(result["matches"]), 1)
            self.assertIn("--status pending", result["matches"][0])

    def test_search_text_retries_wrapped_quoted_query(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "controls.txt").write_text("continue: mew work 1 --live\n", encoding="utf-8")

            result = search_text('"continue:"', str(root), [str(root)], max_matches=5, context_lines=0)

            self.assertEqual(result["query"], "continue:")
            self.assertEqual(result["original_query"], '"continue:"')
            self.assertEqual(len(result["matches"]), 1)
            self.assertIn("continue: mew work", result["matches"][0])

    def test_search_text_include_pattern_does_not_reinclude_sensitive_paths(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / ".mew").mkdir()
            (root / ".mew" / "state.json").write_text("needle in state\n", encoding="utf-8")
            (root / "visible.txt").write_text("needle in visible file\n", encoding="utf-8")

            result = search_text("needle", str(root), [str(root)], max_matches=5, context_lines=1, pattern="*")

            self.assertEqual(len(result["matches"]), 1)
            self.assertIn("visible.txt", result["matches"][0])
            self.assertNotIn(".mew", "\n".join(result["matches"]))

    def test_search_text_splits_space_separated_include_patterns(self):
        from mew.read_tools import search_text

        with tempfile.TemporaryDirectory() as tmp:
            root = Path(tmp)
            (root / "src").mkdir()
            (root / "tests").mkdir()
            (root / "docs").mkdir()
            (root / "src" / "app.py").write_text("needle in source\n", encoding="utf-8")
            (root / "tests" / "test_app.py").write_text("needle in tests\n", encoding="utf-8")
            (root / "docs" / "note.md").write_text("needle in docs\n", encoding="utf-8")
            (root / "outside.txt").write_text("needle outside\n", encoding="utf-8")

            result = search_text(
                "needle",
                str(root),
                [str(root)],
                max_matches=10,
                context_lines=0,
                pattern="src/** tests/** docs/**",
            )

            matches = "\n".join(result["matches"])
            self.assertIn("src/**", result["patterns"])
            self.assertIn("**/src/**", result["patterns"])
            self.assertIn("tests/**", result["patterns"])
            self.assertIn("**/tests/**", result["patterns"])
            self.assertIn("docs/**", result["patterns"])
            self.assertIn("**/docs/**", result["patterns"])
            self.assertIn("src/app.py", matches)
            self.assertIn("tests/test_app.py", matches)
            self.assertIn("docs/note.md", matches)
            self.assertNotIn("outside.txt", matches)

    def test_work_model_rejects_resident_loop_as_verification_command(self):
        from mew.work_loop import normalize_work_model_action

        for command in (
            "mew do 1 --read-only",
            "./mew chat",
            "python -m mew run",
            "uv run mew work 1 --live",
        ):
            action = normalize_work_model_action(
                {"summary": "verify", "action": {"type": "run_tests", "command": command}}
            )
            self.assertEqual(action["type"], "wait", command)
            self.assertIn("resident mew loop", action["reason"])

        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests", "command": "uv run pytest -q"}}
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], "uv run pytest -q")

    def test_work_model_uses_suggested_verify_command_when_configured_verifier_missing(self):
        from mew.work_loop import normalize_work_model_action

        suggested = "uv run python -m unittest tests.test_commands"
        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests"}},
            verify_command="",
            suggested_verify_command=suggested,
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], suggested)

        action = normalize_work_model_action(
            {"summary": "verify", "action": {"type": "run_tests"}},
            verify_command="uv run pytest -q",
            suggested_verify_command=suggested,
        )
        self.assertEqual(action["type"], "run_tests")
        self.assertEqual(action["command"], "uv run pytest -q")

