    def test_quiet_tool_output_progress_mirrors_running_output_to_snapshot(self):
        old_cwd = os.getcwd()
        with tempfile.TemporaryDirectory() as tmp:
            os.chdir(tmp)
            try:
                from mew.commands import (
                    RUNNING_OUTPUT_MIRROR_INTERVAL_SECONDS,
                    work_tool_output_progress,
                    write_work_follow_snapshot,
                )
                import time

                task = {"id": 1, "title": "Quiet running output", "status": "running"}
                session = {
                    "id": 1,
                    "task_id": 1,
                    "status": "active",
                    "title": "Quiet running output",
                    "updated_at": "2026-04-18T00:00:00Z",
                    "tool_calls": [
                        {
                            "id": 3,
                            "tool": "run_command",
                            "status": "running",
                            "started_at": "2026-04-18T00:00:00Z",
                            "parameters": {"command": "printf quiet", "cwd": "."},
                            "result": None,
                        }
                    ],
                }
                with state_lock():
                    state = load_state()
                    state["tasks"].append(task)
                    state["work_sessions"].append(session)
                    save_state(state)

                snapshot_calls = []

                def snapshot():
                    snapshot_calls.append("called")
                    with state_lock():
                        state = load_state()
                        current_session = state["work_sessions"][0]
                        current_task = state["tasks"][0]
                        resume = build_work_session_resume(current_session, task=current_task)
                    write_work_follow_snapshot(
                        SimpleNamespace(live=True, follow=True, quiet=True),
                        {"steps": [], "stop_reason": "work_already_running"},
                        current_session,
                        current_task,
                        resume,
                        force=True,
                    )

                emit = work_tool_output_progress(None, 3, session_id=1, on_state_update=snapshot)

                emit("stdout", "quiet partial\n")
                emit("stdout", "buffered partial\n")

                data = json.loads(Path(".mew/follow/latest.json").read_text(encoding="utf-8"))
                command_cell = next(cell for cell in data["cells"] if cell["kind"] == "command")
                self.assertTrue(data["resume"]["commands"][0]["output_running"])
                self.assertIn("quiet partial", data["resume"]["commands"][0]["stdout"])
                self.assertNotIn("buffered partial", data["resume"]["commands"][0]["stdout"])
                self.assertIn("quiet partial", "\n".join(command_cell["tail"][0]["lines"]))
                self.assertEqual(data["session_updated_at"], "2026-04-18T00:00:00Z")
                self.assertEqual(len(snapshot_calls), 1)

                time.sleep(RUNNING_OUTPUT_MIRROR_INTERVAL_SECONDS + 0.1)

                self.assertEqual(len(snapshot_calls), 2)
                data = json.loads(Path(".mew/follow/latest.json").read_text(encoding="utf-8"))
                self.assertIn("buffered partial", data["resume"]["commands"][0]["stdout"])
                self.assertEqual(data["session_updated_at"], "2026-04-18T00:00:00Z")
            finally:
                os.chdir(old_cwd)

    def test_work_session_suppresses_resolved_approval_memory_next_step(self):
        from mew.work_session import build_work_session_resume

        session = {
            "id": 1,
            "task_id": 1,
            "status": "active",
            "title": "Approval resolved",
            "updated_at": "2026-04-18T00:00:03Z",
            "model_turns": [
                {
                    "id": 1,
                    "status": "completed",
                    "started_at": "2026-04-18T00:00:00Z",
                    "finished_at": "2026-04-18T00:00:01Z",
                    "tool_call_id": 1,
                    "decision_plan": {
                        "working_memory": {
                            "hypothesis": "A write is ready.",
                            "next_step": "After reentry, wait for approval or rejection of tool_call_id 1.",
                        }
                    },
                }
            ],
            "tool_calls": [
                {
                    "id": 1,
                    "tool": "edit_file",
                    "status": "completed",
                    "approval_status": "applied",
                    "parameters": {"path": "notes.md", "old": "before", "new": "after"},
                    "result": {"path": "notes.md", "dry_run": True, "changed": True},
                },
                {
                    "id": 2,
                    "tool": "edit_file",
                    "status": "completed",
                    "parameters": {"path": "notes.md", "old": "before", "new": "after", "apply": True},
                    "result": {"path": "notes.md", "dry_run": False, "changed": True},
                },
            ],
        }

        resume = build_work_session_resume(session, task={"id": 1, "title": "Approval resolved"})

        self.assertEqual(resume["pending_approvals"], [])
        memory = resume["working_memory"]
        self.assertEqual(memory["hypothesis"], "A write is ready.")
        self.assertEqual(memory.get("next_step"), "")
        self.assertTrue(memory["resolved_pending_approval"])
        self.assertEqual(memory["resolved_pending_approval_tool_call_id"], 1)
        self.assertIn("pending approval already applied", memory["resolved_pending_approval_state"])
        self.assertEqual(memory["latest_tool_call_id"], 2)

